UPDATE archivio_items SET abstract = 'Da poco approvato dal Ministero  della Comunicazione il codice di autoregolamentazione tv rispetto ai minori. Servizio.   In studio il Ministro Gasparri, i direttori del TG1 (Clemente Mimun) e del TG5 (Enrico Mentana), la responsabile DS infanzia adolescenza Anna Serafini. Episodi di ingerenza giornalistica (Aosta), attacco a Michele Cucuzza. Le svariate funzioni della TV nei confronti dei bambini. Maria Rita Minuzzi pres. Movimento italiano genitori. La violenza in tv. 2.42.15 I cartoni animati violenti. La lettera di Erika.. Il programma non finisce per qualche minuto.' WHERE id_originale = 4253;
UPDATE archivio_items SET abstract = 'Un ragazzo ripercorre i momenti salienti della stioria d''amore con una ragazza, sfogliando i petali di una margherita gialla: ad ogni petalo corrisponte una situazione nella quale lei dimostra di amarlo oppure una nella quale lui si sente trascurato. L''ultima scena si svolge in un bar e lei, arrabbiatissima, gli rovescia un bicchiere in faccia e se na va: per fortuna nel fiore avanza ancora un petalo..' WHERE id_originale = 4265;
